instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "Generated trajectory commands from the Trajectory Generator Service are transmitted via the Control Application to the physical crane’s motor controllers; the continuous validation service may trigger alerts sent to the operator through the Grafana dashboard."
]

